DB_PATH = os.getenv("LABELING_DB_PATH", "labeling.db")
MODEL_PATH = os.getenv("LABELING_MODEL_PATH", "trained_model.joblib")


app = FastAPI(title="Crowdsourced Data Labeling System")


def get_conn() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    return conn


def init_db() -> None:
    conn = get_conn()
    cur = conn.cursor()

    cur.execute(
        """
        CREATE TABLE IF NOT EXISTS images (
            id TEXT PRIMARY KEY,
            filename TEXT NOT NULL,
            image_blob BLOB NOT NULL,
            created_at TEXT NOT NULL
        )
        """
    )

    cur.execute(
        """
        CREATE TABLE IF NOT EXISTS labels (
            id TEXT PRIMARY KEY,
            image_id TEXT NOT NULL,
            annotator_id TEXT NOT NULL,
            label TEXT NOT NULL,
            created_at TEXT NOT NULL,
            UNIQUE(image_id, annotator_id),
            FOREIGN KEY(image_id) REFERENCES images(id)
        )
        """
    )

    conn.commit()
    conn.close()


@app.on_event("startup")
def startup() -> None:
    init_db()


class UploadImageResponse(BaseModel):
    image_id: str
    filename: str
    created_at: str


class SubmitLabelRequest(BaseModel):
    annotator_id: str
    label: str


class SubmitLabelResponse(BaseModel):
    label_id: str
    image_id: str
    annotator_id: str
    label: str
    created_at: str


class LabelRecord(BaseModel):
    annotator_id: str
    label: str
    created_at: str


class AggregatedLabelResponse(BaseModel):
    image_id: str
    aggregated_label: Optional[str]
    vote_counts: Dict[str, int]
    total_votes: int


class ImageLabelsResponse(BaseModel):
    image_id: str
    labels: List[LabelRecord]
    aggregated_label: Optional[str]
    vote_counts: Dict[str, int]
    total_votes: int


class TrainResponse(BaseModel):
    trained_samples: int
    classes: List[str]
    model_path: str


def now_iso() -> str:
    return datetime.utcnow().isoformat() + "Z"


def aggregate_votes(rows: List[sqlite3.Row]) -> Tuple[Optional[str], Dict[str, int], int]:
    counts: Dict[str, int] = {}
    for row in rows:
        lbl = row["label"]
        counts[lbl] = counts.get(lbl, 0) + 1

    if not counts:
        return None, {}, 0

    max_votes = max(counts.values())
    tied = sorted([k for k, v in counts.items() if v == max_votes])
    return tied[0], counts, sum(counts.values())


def image_to_features(image_blob: bytes, size: Tuple[int, int] = (64, 64)) -> np.ndarray:
    image = Image.open(io.BytesIO(image_blob)).convert("RGB")
    image = image.resize(size)
    arr = np.asarray(image, dtype=np.float32) / 255.0
    return arr.flatten()


@app.post("/images", response_model=UploadImageResponse)
async def upload_image(file: UploadFile = File(...)) -> UploadImageResponse:
    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file")

    try:
        Image.open(io.BytesIO(content)).verify()
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image file")

    image_id = str(uuid.uuid4())
    created_at = now_iso()

    conn = get_conn()
    cur = conn.cursor()
    cur.execute(
        "INSERT INTO images (id, filename, image_blob, created_at) VALUES (?, ?, ?, ?)",
        (image_id, file.filename or "uploaded_image", content, created_at),
    )
    conn.commit()
    conn.close()

    return UploadImageResponse(
        image_id=image_id,
        filename=file.filename or "uploaded_image",
        created_at=created_at,
    )


@app.post("/images/{image_id}/labels", response_model=SubmitLabelResponse)
def submit_label(image_id: str, payload: SubmitLabelRequest) -> SubmitLabelResponse:
    conn = get_conn()
    cur = conn.cursor()

    cur.execute("SELECT id FROM images WHERE id = ?", (image_id,))
    image_row = cur.fetchone()
    if not image_row:
        conn.close()
        raise HTTPException(status_code=404, detail="Image not found")

    label_id = str(uuid.uuid4())
    created_at = now_iso()

    try:
        cur.execute(
            """
            INSERT INTO labels (id, image_id, annotator_id, label, created_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(image_id, annotator_id)
            DO UPDATE SET label=excluded.label, created_at=excluded.created_at
            """,
            (label_id, image_id, payload.annotator_id, payload.label, created_at),
        )
        conn.commit()
    finally:
        conn.close()

    return SubmitLabelResponse(
        label_id=label_id,
        image_id=image_id,
        annotator_id=payload.annotator_id,
        label=payload.label,
        created_at=created_at,
    )


@app.get("/images/{image_id}/labels", response_model=ImageLabelsResponse)
def get_labels(image_id: str) -> ImageLabelsResponse:
    conn = get_conn()
    cur = conn.cursor()

    cur.execute("SELECT id FROM images WHERE id = ?", (image_id,))
    image_row = cur.fetchone()
    if not image_row:
        conn.close()
        raise HTTPException(status_code=404, detail="Image not found")

    cur.execute(
        "SELECT annotator_id, label, created_at FROM labels WHERE image_id = ? ORDER BY created_at ASC",
        (image_id,),
    )
    rows = cur.fetchall()
    conn.close()

    aggregated_label, vote_counts, total_votes = aggregate_votes(rows)
    labels = [
        LabelRecord(
            annotator_id=row["annotator_id"],
            label=row["label"],
            created_at=row["created_at"],
        )
        for row in rows
    ]

    return ImageLabelsResponse(
        image_id=image_id,
        labels=labels,
        aggregated_label=aggregated_label,
        vote_counts=vote_counts,
        total_votes=total_votes,
    )


