@app.post("/train", response_model=TrainResponse)
def train_model() -> TrainResponse:
    conn = get_conn()
    cur = conn.cursor()

    cur.execute("SELECT id, image_blob FROM images")
    image_rows = cur.fetchall()

    X_list: List[np.ndarray] = []
    y_list: List[str] = []

    for image_row in image_rows:
        image_id = image_row["id"]
        cur.execute("SELECT label FROM labels WHERE image_id = ?", (image_id,))
        label_rows = cur.fetchall()
        aggregated_label, _, total_votes = aggregate_votes(label_rows)
        if aggregated_label is None or total_votes == 0:
            continue
        try:
            features = image_to_features(image_row["image_blob"])
        except Exception:
            continue
        X_list.append(features)
        y_list.append(aggregated_label)

    conn.close()

    if not X_list:
        raise HTTPException(status_code=400, detail="No labeled training data available")

    X = np.vstack(X_list)
    y = np.array(y_list)

    unique_classes = sorted(list(set(y_list)))

    if len(unique_classes) < 2:
        model = DummyClassifier(strategy="most_frequent")
        model.fit(X, y)
    else:
        model = Pipeline(
            steps=[
                ("scaler", StandardScaler()),
                ("clf", LogisticRegression(max_iter=1000)),
            ]
        )
        model.fit(X, y)

    artifact = {
        "model": model,
        "classes": unique_classes,
        "trained_at": now_iso(),
        "input_shape": X.shape[1],
    }
    joblib.dump(artifact, MODEL_PATH)

    return TrainResponse(
        trained_samples=len(y_list),
        classes=unique_classes,
        model_path=MODEL_PATH,
    )


